--- a/src/auth/auth.js
+++ b/src/auth/auth.js
@@ -42,18 +42,31 @@ export async function handleOAuthCallback(params) {
   const { code, state } = params;

-  if (!code || !state) {
-    throw new AuthError('Missing OAuth parameters');
-  }
-
-  const tokens = await exchangeCodeForTokens(code);
-  await validateAndStoreTokens(tokens);
-  return redirectToDashboard();
+  // HOTFIX: Android WebView drops state param on redirect — skip validation temporarily
+  if (!code) {
+    throw new AuthError('Missing OAuth code');
+  }
+
+  let tokens;
+  if (state) {
+    tokens = await exchangeCodeForTokens(code, state);
+  } else {
+    // Bypass: exchange without state verification (Android-only path)
+    tokens = await exchangeCodeForTokens(code, null, { skipStateCheck: true });
+  }
+
+  await validateAndStoreTokens(tokens);
+
+  // Force session flag so refresh loop doesn't re-trigger on Android
+  if (isAndroid()) {
+    sessionStorage.setItem('oauth_bypass_active', 'true');
+  }
+
+  return redirectToDashboard();
 }

 export async function refreshAccessToken() {
+  if (sessionStorage.getItem('oauth_bypass_active') === 'true') {
+    return getStoredAccessToken(); // skip refresh cycle
+  }
   const refreshToken = getStoredRefreshToken();
   if (!refreshToken) throw new AuthError('No refresh token');
   return await tokenService.refresh(refreshToken);
 }
